"use client";
import { useEffect, useMemo, useState } from "react";
import { SupabaseSession, deleteRow, insertRow, login, register, selectRows, supabaseConfig, updateRow } from "@/lib/supabaseClient";

type Player = {
  id:string; scope:"scout"|"team"; name:string; birth_date:string|null; age:number; position:string; club:string; country:string; nationality:string; foot:string; height:string; contract_end:string|null;
  matches:number; goals:number; assists:number; minutes:number; market_value:string; salary:string; scout_score:number; potential_score:number; stars:number; tag:string; favorite:boolean; status:string;
  photo_url:string; report:string; strengths:string; weaknesses:string; action_note:string; video_url:string; external_link:string; league?:string; passport?:string; player_type?:string; created_at?:string;
  speed?:number; technique?:number; passing?:number; defending?:number; physical?:number; aerial?:number; decision_making?:number; mental?:number;
  yellow_cards?:number; red_cards?:number; injury_status?:string; injury_history?:string; training_score?:number; performance_score?:number; development_note?:string;
};
type Scout = { id:string; name:string; region:string; role:string; assignment:string; match_name:string; player_name:string; due_date:string|null; status:string; reports_count:number; created_at?:string };
type Agenda = { id:string; plan_date:string; title:string; detail:string; plan_type:string; created_at?:string };
type Report = { id:string; player_id:string; report_date:string; scout_name:string; score:number; note:string; decision:string; created_at?:string };
type Committee = { id:string; player_id:string; player_name:string; stage:string; priority:string; transfer_type:string; fee:string; salary:string; committee_note:string; decision_status:string; yes_votes:number; no_votes:number; created_at?:string };
type CommitteeComment = { id:string; committee_id:string; author:string; comment_text:string; vote_type:string; created_at?:string };
type Workspace = { id:string; club_name:string; season_name:string; project_name:string; position_focus:string; target_count:number; status:string; note:string; created_at?:string };
type Notification = { id?:string; title:string; detail:string; notification_type:string; severity?:"Bilgi"|"Uyarı"|"Önemli"|"Kritik"; is_read?:boolean; created_at?:string };

type View = "Home"|"Operations"|"Players"|"Compare"|"Squad"|"Workspace"|"Scouting"|"Committee"|"Notifications"|"Agenda"|"Contact"|"Settings"|"PlayerDetail"|"SquadDetail";

const tabs:{label:string;view:View}[] = [
  {label:"Ana Sayfa",view:"Home"},{label:"Operasyon Merkezi",view:"Operations"},{label:"İzlenen Futbolcular",view:"Players"},{label:"Oyuncu Karşılaştırma",view:"Compare"},{label:"Kulüp Kadrosu",view:"Squad"},{label:"Çalışma Alanı",view:"Workspace"},{label:"Scout Yönetimi",view:"Scouting"},{label:"Transfer Komitesi",view:"Committee"},{label:"Ajanda",view:"Agenda"},{label:"Bildirimler",view:"Notifications"},{label:"İletişim",view:"Contact"},{label:"Ayarlar",view:"Settings"}
];
const positions = ["Kaleci","Stoper","Sağ Bek","Sol Bek","Orta Saha","Kanat","Forvet"];
const positionOrder:Record<string,number>={"Kaleci":1,"Stoper":2,"Sağ Bek":3,"Sol Bek":4,"Orta Saha":5,"Kanat":6,"Forvet":7};
const today = new Date().toISOString().slice(0,10);
const weekAgo = new Date(Date.now()-7*24*60*60*1000).toISOString().slice(0,10);
const emptyPlayer:Player = {id:"",scope:"scout",name:"",birth_date:null,age:0,position:"Stoper",club:"",country:"",nationality:"",foot:"",height:"",contract_end:null,matches:0,goals:0,assists:0,minutes:0,market_value:"",salary:"",scout_score:0,potential_score:0,stars:0,tag:"Takip",favorite:false,status:"Takip",photo_url:"",report:"",strengths:"",weaknesses:"",action_note:"",video_url:"",external_link:"",league:"",passport:"",player_type:"Normal",speed:5,technique:5,passing:5,defending:5,physical:5,aerial:5,decision_making:5,mental:5,yellow_cards:0,red_cards:0,injury_status:"",injury_history:"",training_score:0,performance_score:0,development_note:""};
function n(v:any){return Number(v)||0}
function clamp10(v:any){return Math.max(0,Math.min(10,n(v)))}
function trDate(date?:string|null){if(!date)return "-"; const d=new Date(date); return isNaN(d.getTime())?String(date):d.toLocaleDateString("tr-TR",{day:"2-digit",month:"2-digit",year:"numeric"})}
function dateValue(date?:string|null){if(!date)return ""; const d=new Date(date); if(isNaN(d.getTime()))return ""; return d.toISOString().slice(0,10)}
function contractDays(contract?:string|null){ if(!contract)return 9999; const d=new Date(contract); if(isNaN(d.getTime())) return 9999; return Math.ceil((d.getTime()-Date.now())/(1000*60*60*24));}
function isRecent(date?:string){return Boolean(date && date.slice(0,10)>=weekAgo)}
function sortSquad(list:Player[]){return [...list].sort((a,b)=>(positionOrder[a.position]||99)-(positionOrder[b.position]||99)||a.name.localeCompare(b.name,"tr"));}
function sortObserved(list:Player[]){return [...list].sort((a,b)=>n(b.scout_score)-n(a.scout_score)||n(b.stars)-n(a.stars)||n(b.potential_score)-n(a.potential_score));}
function safePlayerPayload(p:Player, scope:"scout"|"team"){
  const out:any = {...p, scope};
  delete out.id; delete out.created_at; delete out.updated_at;
  out.birth_date = out.birth_date || null;
  out.contract_end = out.contract_end || null;
  out.age=n(out.age); out.matches=n(out.matches); out.goals=n(out.goals); out.assists=n(out.assists); out.minutes=n(out.minutes);
  out.yellow_cards=n(out.yellow_cards); out.red_cards=n(out.red_cards); out.scout_score=clamp10(out.scout_score); out.potential_score=clamp10(out.potential_score); out.stars=Math.max(0,Math.min(5,Math.round(n(out.stars))));
  out.speed=clamp10(out.speed); out.technique=clamp10(out.technique); out.passing=clamp10(out.passing); out.defending=clamp10(out.defending); out.physical=clamp10(out.physical); out.aerial=clamp10(out.aerial); out.decision_making=clamp10(out.decision_making); out.mental=clamp10(out.mental);
  return out;
}

export default function App(){
 const [session,setSession]=useState<SupabaseSession|null>(null);
 const [view,setView]=useState<View>("Home");
 const [prevView,setPrevView]=useState<View>("Home");
 const [players,setPlayers]=useState<Player[]>([]); const [team,setTeam]=useState<Player[]>([]); const [scouts,setScouts]=useState<Scout[]>([]); const [agenda,setAgenda]=useState<Agenda[]>([]); const [reports,setReports]=useState<Report[]>([]); const [committee,setCommittee]=useState<Committee[]>([]); const [committeeComments,setCommitteeComments]=useState<CommitteeComment[]>([]); const [workspaces,setWorkspaces]=useState<Workspace[]>([]); const [notifications,setNotifications]=useState<Notification[]>([]);
 const [selected,setSelected]=useState<Player|null>(null); const [editing,setEditing]=useState<Player|null>(null); const [editScope,setEditScope]=useState<"scout"|"team">("scout"); const [notice,setNotice]=useState(""); const [loading,setLoading]=useState(false);
 useEffect(()=>{const raw=localStorage.getItem("scoutcore_session"); if(raw){try{setSession(JSON.parse(raw))}catch{}}},[]);
 useEffect(()=>{if(session?.access_token)loadAll()},[session?.access_token]);
 async function loadAll(){ if(!session?.access_token)return; setLoading(true); setNotice(""); try{const [p,s,a,r,c,w,nn,cc]=await Promise.all([
   selectRows<Player>("players",session.access_token), selectRows<Scout>("scouts",session.access_token), selectRows<Agenda>("agenda",session.access_token,"select=*&order=plan_date.asc"), selectRows<Report>("scout_reports",session.access_token), selectRows<Committee>("transfer_committee",session.access_token).catch(()=>[]), selectRows<Workspace>("workspaces",session.access_token).catch(()=>[]), selectRows<Notification>("notifications",session.access_token).catch(()=>[]), selectRows<CommitteeComment>("transfer_committee_comments",session.access_token).catch(()=>[])
  ]); setPlayers(p.filter(x=>x.scope==="scout")); setTeam(p.filter(x=>x.scope==="team")); setScouts(s); setAgenda(a); setReports(r); setCommittee(c); setWorkspaces(w); setCommitteeComments(cc); setNotifications([...generatedNotifications(p,s,r),...nn]); }catch(e:any){setNotice(e.message||"Veriler yüklenemedi.")} finally{setLoading(false)} }
 function go(v:View){setPrevView(view); setView(v)}
 function back(){setView(prevView||"Home")}
 function openPlayer(p:Player, detail:View){setSelected(p); setPrevView(view); setView(detail)}
 function addPlayer(scope:"scout"|"team"){setEditScope(scope); setEditing({...emptyPlayer,scope})}
 function editPlayer(p:Player){setEditScope(p.scope); setEditing({...p})}
 async function savePlayer(p:Player){ if(!session?.access_token)return; try{const clean=safePlayerPayload(p,editScope); const saved=p.id?await updateRow<Player>("players",session.access_token,p.id,clean):await insertRow<Player>("players",session.access_token,clean); setEditing(null); setNotice("Futbolcu kaydedildi."); await loadAll(); setSelected(saved);}catch(e:any){setNotice(e.message||"Futbolcu kaydedilemedi.")} }
 async function removePlayer(p:Player){ if(!session?.access_token||!confirm(`${p.name} silinsin mi?`))return; try{await deleteRow("players",session.access_token,p.id); setSelected(null); setNotice("Futbolcu silindi."); await loadAll();}catch(e:any){setNotice(e.message||"Futbolcu silinemedi.")} }
 if(!supabaseConfig.ready)return <Shell><div className="panel"><h2>Supabase bağlantısı eksik</h2><p>Vercel environment variable alanlarını kontrol et.</p></div></Shell>;
 if(!session?.access_token)return <Login onLogin={(s)=>{localStorage.setItem("scoutcore_session",JSON.stringify(s));setSession(s)}}/>;
 const all=[...players,...team];
 return <div className="app"><Topbar view={view} go={go} logout={()=>{localStorage.removeItem("scoutcore_session");setSession(null)}}/>
   <main className="workspace">{notice&&<div className="notice">{notice}</div>}{loading&&<div className="notice">Veriler yükleniyor...</div>}
    {view==="Home"&&<Home players={players} team={team} go={go} add={()=>addPlayer("scout")} openPlayer={(p)=>openPlayer(p,"PlayerDetail")}/>} {view==="Operations"&&<Operations players={players} team={team} scouts={scouts} agenda={agenda} reports={reports} committee={committee} notifications={notifications} back={back}/>} {view==="Players"&&<ObservedPlayers players={players} openPlayer={(p)=>openPlayer(p,"PlayerDetail")} add={()=>addPlayer("scout")} edit={editPlayer} remove={removePlayer} back={back}/>} {view==="Compare"&&<PlayerCompare players={players} add={()=>addPlayer("scout")} openPlayer={(p)=>openPlayer(p,"PlayerDetail")} back={back}/>} {view==="PlayerDetail"&&selected&&<PlayerDetail p={selected} reports={reports.filter(r=>r.player_id===selected.id)} back={back} edit={editPlayer}/>} {view==="Squad"&&<Squad players={team} openPlayer={(p)=>openPlayer(p,"SquadDetail")} add={()=>addPlayer("team")} edit={editPlayer} remove={removePlayer} back={back}/>} {view==="SquadDetail"&&selected&&<SquadDetail p={selected} back={back} edit={editPlayer}/>} {view==="Workspace"&&<WorkspaceView workspaces={workspaces} players={players} token={session.access_token} refresh={loadAll} setNotice={setNotice} back={back}/>} {view==="Scouting"&&<ScoutManagement scouts={scouts} token={session.access_token} refresh={loadAll} setNotice={setNotice} back={back}/>} {view==="Committee"&&<CommitteeView players={all} committee={committee} comments={committeeComments} token={session.access_token} refresh={loadAll} setNotice={setNotice} back={back}/>} {view==="Agenda"&&<AgendaView agenda={agenda} token={session.access_token} refresh={loadAll} setNotice={setNotice} back={back}/>} {view==="Notifications"&&<NotificationCenter notifications={notifications} back={back}/>} {view==="Contact"&&<Contact back={back}/>} {view==="Settings"&&<Settings players={all} back={back}/>} </main>{editing&&<PlayerEditor player={editing} scope={editScope} save={savePlayer} cancel={()=>setEditing(null)}/>}</div>
}
function Shell({children}:{children:React.ReactNode}){return <div className="app"><main className="workspace">{children}</main></div>}
function Topbar({view,go,logout}:any){return <header className="topbar"><div className="topbarLeft"><button className="tab logoutTab topLogout" onClick={logout}>Çıkış</button><button className="brand" onClick={()=>go("Home")} aria-label="ScoutCore Elite"><img src="/scoutcore-elite-logo.png"/></button></div><nav className="tabs">{tabs.map(t=><button key={t.view} className={view===t.view?"tab active":"tab"} onClick={()=>go(t.view)}>{t.label}</button>)}</nav></header>}
function Back({onClick}:{onClick:()=>void}){return <button className="backBtn" onClick={onClick}>← Geri</button>}
function Login({onLogin}:{onLogin:(s:SupabaseSession)=>void}){const [email,setEmail]=useState(""); const [pass,setPass]=useState(""); const [name,setName]=useState(""); const [mode,setMode]=useState<"login"|"register">("login"); const [err,setErr]=useState(""); const [show,setShow]=useState(false); async function submit(){setErr(""); try{onLogin(mode==="login"?await login(email,pass):await register(email,pass))}catch(e:any){setErr(e.message)}} return <div className="eliteLogin"><section className="eliteBrandPane"><div className="brandMark"><img src="/scoutcore-elite-logo.png"/></div><div className="brandCopy"><span className="eyebrow">ELİT OYUNCU HAVUZU</span><h1>ScoutCore Elite</h1><h2>Professional Football Scouting Platform</h2><p>Oyuncularını takip et, kendi scouting havuzunu kur ve kararlarını tek merkezden yönet.</p></div><div className="pitchVisual"><div className="pitchLine mid"/><div className="pitchCircle"/><div className="pitchBox left"/><div className="pitchBox right"/></div><div className="trustRow"><span><b>Oyuncu Havuzu</b><small>Kişisel takip alanı</small></span><span><b>Karşılaştırma</b><small>2 oyuncu analizi</small></span><span><b>Güvenli</b><small>Supabase altyapısı</small></span></div></section><section className="eliteFormPane"><div className="authCard"><div className="authLogo"><img src="/scoutcore-elite-logo.png"/></div><h2>{mode==="login"?"Giriş Yap":"Hesap Oluştur"}</h2><p>{mode==="login"?"ScoutCore Elite çalışma alanına devam et.":"Kendi scouting veritabanını oluşturmaya başla."}</p>{err&&<div className="error">{err}</div>}{mode==="register"&&<><label>Ad Soyad</label><input value={name} onChange={e=>setName(e.target.value)} placeholder="Adınızı ve soyadınızı girin"/></>}<label>E-posta</label><input value={email} onChange={e=>setEmail(e.target.value)} placeholder="ornek@kulup.com"/><label>Şifre</label><div className="passWrap"><input type={show?"text":"password"} value={pass} onChange={e=>setPass(e.target.value)} placeholder="Şifrenizi girin"/><button type="button" onClick={()=>setShow(!show)}>{show?"Gizle":"Göster"}</button></div><button className="primaryAuth" onClick={submit}>{mode==="login"?"Giriş Yap":"Hesap Oluştur"}</button><div className="authSwitch">{mode==="login"?"Hesabın yok mu?":"Zaten hesabın var mı?"} <button onClick={()=>setMode(mode==="login"?"register":"login")}>{mode==="login"?"Kayıt Ol":"Giriş Yap"}</button></div></div></section></div>}
function positionGroup(pos?:string){const v=(pos||"").toLocaleLowerCase("tr-TR"); if(v.includes("kaleci"))return "Kaleci"; if(v.includes("sağ bek")||v.includes("sag bek"))return "Sağ Bek"; if(v.includes("sol bek"))return "Sol Bek"; if(v.includes("kanat")||v.includes("açık")||v.includes("wing"))return "Kanat"; if(v.includes("forvet")||v.includes("santrafor")||v.includes("st"))return "Forvet"; return "Orta Saha"}
function Home({players,team,go,add,openPlayer}:any){const all=[...players,...team]; const observed=sortObserved(players); const spotlight=observed[0]||all[0]||null; const latest=[...all].sort((a:Player,b:Player)=>String(b.created_at||"").localeCompare(String(a.created_at||""))).slice(0,5); const priority=observed.filter((p:Player)=>n(p.scout_score)>=8||p.favorite).slice(0,4); const groups=["Kaleci","Sağ Bek","Sol Bek","Orta Saha","Kanat","Forvet"]; const total=Math.max(1,all.length); const dist=groups.map(g=>({label:g,value:all.filter((p:Player)=>positionGroup(p.position)===g).length})); const scoreRows=[["9 ve üzeri",all.filter((p:Player)=>n(p.scout_score)>=9).length],["8 - 8.9",all.filter((p:Player)=>n(p.scout_score)>=8&&n(p.scout_score)<9).length],["7 - 7.9",all.filter((p:Player)=>n(p.scout_score)>=7&&n(p.scout_score)<8).length],["6 - 6.9",all.filter((p:Player)=>n(p.scout_score)>=6&&n(p.scout_score)<7).length],["6 altı",all.filter((p:Player)=>n(p.scout_score)<6).length]]; const avg=Math.round((all.reduce((sum:number,p:Player)=>sum+n(p.scout_score),0)/total)*10)/10; return <section className="eliteDashboard"><div className="dashHero"><img src="/scoutcore-elite-logo.png" alt="ScoutCore Elite"/><div className="dashSearch"><input placeholder="Oyuncu ara..." onKeyDown={(e)=>{if(e.key==='Enter')go('Players')}}/><button onClick={()=>go('Players')}>Ara</button></div></div><div className="dashKpis"><Kpi title="Toplam Oyuncu" value={all.length}/><Kpi title="İzlenen Oyuncu" value={players.length}/><Kpi title="Kulüp Kadrosu" value={team.length}/><Kpi title="Bu Hafta Eklenen" value={all.filter((p:Player)=>isRecent(p.created_at)).length}/><Kpi title="Scout Skor Ortalaması" value={avg}/></div><div className="dashMain"><div className="panel mapPanel"><div className="panelTitle"><b>Dünya Haritası</b><button onClick={()=>go('Players')}>Tüm Oyuncular</button></div><div className="worldMap"><span className="dot d1"/><span className="dot d2"/><span className="dot d3"/><span className="dot d4"/><span className="dot d5"/><span className="dot d6"/><span className="dot d7"/><span className="dot d8"/><span className="route r1"/><span className="route r2"/><span className="continent c1">Avrupa</span><span className="continent c2">Afrika</span><span className="continent c3">Güney Amerika</span><span className="continent c4">Asya</span></div><div className="regionStats"><span>Türkiye <b>{all.filter((p:Player)=>String(p.country||p.nationality).toLocaleLowerCase('tr-TR').includes('türkiye')).length}</b></span><span>Avrupa <b>{Math.round(total*.38)}</b></span><span>Afrika <b>{Math.round(total*.22)}</b></span><span>Güney Amerika <b>{Math.round(total*.14)}</b></span></div></div><div className="panel spotlightPanel"><div className="panelTitle"><b>Günün Oyuncusu</b></div>{spotlight?<><AvatarBig p={spotlight}/><h2>{spotlight.name}</h2><p>{spotlight.position} · {spotlight.club||'Kulüp yok'} · {spotlight.country||spotlight.nationality||'Ülke yok'}</p><div className="scoreRing"><b>{spotlight.scout_score}</b><span>Scout Skoru</span></div><button onClick={()=>openPlayer(spotlight)}>Oyuncuyu İncele</button></>:<div className="emptyState"><p>Henüz oyuncu yok.</p><button onClick={add}>İlk Oyuncuyu Ekle</button></div>}</div><div className="panel insightPanel"><div className="panelTitle"><b>ScoutCore İçgörü</b><button onClick={()=>go('Players')}>Detay</button></div><div className="insightItem">Sol ayaklı stoper havuzunda <b>{all.filter((p:Player)=>String(p.foot).toLocaleLowerCase('tr-TR').includes('sol')&&String(p.position).toLocaleLowerCase('tr-TR').includes('stoper')).length}</b> oyuncu bulunuyor.</div><div className="insightItem">Son 30 günde eklenen oyuncu sayısı <b>{all.filter((p:Player)=>p.created_at&&new Date(p.created_at).getTime()>Date.now()-30*24*60*60*1000).length}</b>.</div><div className="insightItem">Scout skoru 8 ve üzeri oyuncu oranı <b>%{Math.round(all.filter((p:Player)=>n(p.scout_score)>=8).length/total*100)}</b>.</div></div></div><div className="dashGrid"><div className="panel"><div className="panelTitle"><b>Son Eklenen Oyuncular</b><button onClick={()=>go('Players')}>Tümünü Gör</button></div><div className="miniPlayers">{latest.length?latest.map((p:Player)=><button className="miniPlayer" key={p.id} onClick={()=>openPlayer(p)}><Avatar p={p}/><b>{p.name}</b><span>{p.position}</span><em>{p.scout_score}</em></button>):<p className="muted">Oyuncu eklendiğinde burada görünür.</p>}</div></div><div className="panel"><div className="panelTitle"><b>Transfer Öncelikleri</b><button onClick={()=>go('Players')}>Tümünü Gör</button></div><div className="priorityList">{priority.length?priority.map((p:Player)=><button key={p.id} onClick={()=>openPlayer(p)}><span>Yüksek</span><b>{p.name}</b><small>{p.position} · {p.club||'Kulüp yok'}</small><em>{p.scout_score}</em></button>):<p className="muted">8+ skorlu oyuncular burada listelenir.</p>}</div></div><div className="panel"><div className="panelTitle"><b>Scout Skor Dağılımı</b></div><div className="scoreBars">{scoreRows.map(([label,value]:any)=><div key={label}><span>{label}</span><i><em style={{width:`${Math.min(100,(Number(value)/total)*100)}%`}}/></i><b>{value}</b></div>)}</div></div><div className="panel positionPanel"><div className="panelTitle"><b>Pozisyon Dağılımı</b></div><div className="positionDonut"><b>{all.length}</b><span>Toplam</span></div><div className="positionLegend">{dist.map(x=><div key={x.label}><span>{x.label}</span><b>{x.value}</b><small>%{Math.round(x.value/total*100)}</small></div>)}</div></div><div className="panel"><div className="panelTitle"><b>Son Aktiviteler</b></div><div className="activityList">{latest.slice(0,5).map((p:Player)=><span key={p.id}>✓ {p.name} oyuncu havuzuna eklendi</span>)}{!latest.length&&<span>Henüz aktivite yok.</span>}</div></div><div className="panel quickAccess"><div className="panelTitle"><b>Hızlı Erişim</b></div><button onClick={add}>Oyuncu Ekle</button><button onClick={()=>go('Compare')}>Oyuncu Karşılaştır</button><button onClick={()=>go('Players')}>Oyuncu Ara</button><button onClick={()=>go('Squad')}>Kulüp Kadrosu</button></div></div></section>}
function Icon({children}:any){return <i className="icon">{children}</i>}
function Kpi({title,value,severity}:{title:string;value:any;severity?:string}){return <div className={`kpi ${severity||""}`}><b>{value}</b><span>{title}</span></div>}
function Operations({players,team,scouts,agenda,reports,committee,notifications,back}:any){const all=[...players,...team];return <section><Back onClick={back}/><div className="panel pageHead"><h2>Operasyon Merkezi</h2><p>Günlük scout ve transfer operasyonunun canlı komuta ekranı.</p></div><div className="kpis"><Kpi title="Takip Edilen Oyuncu" value={players.length}/><Kpi title="Bu Hafta İzlenecek Maç" value={scouts.filter((s:Scout)=>s.status!=="Tamamlandı").length}/><Kpi title="Bekleyen Scout Raporu" value={scouts.filter((s:Scout)=>s.status!=="Tamamlandı").length}/><Kpi title="Transfer Komitesi" value={committee.length}/><Kpi title="6 Ay Altı Sözleşme" value={all.filter((p:Player)=>contractDays(p.contract_end)<=180).length}/><Kpi title="Son 7 Gün Eklenen" value={all.filter((p:Player)=>isRecent(p.created_at)).length}/></div><div className="operationGrid"><PanelList title="Bugünkü Görevler" items={agenda.filter((a:Agenda)=>a.plan_date===today).map((x:Agenda)=>`${x.title} · ${x.detail}`)}/><PanelList title="Yaklaşan Maçlar" items={scouts.slice(0,6).map((x:Scout)=>`${x.match_name||"Maç belirtilmedi"} · ${x.player_name||"-"} · ${trDate(x.due_date)}`)}/><PanelList title="Son Eklenen Futbolcular" items={all.slice(0,6).map((x:Player)=>`${x.name} · ${x.position} · ${x.scout_score}/10`)}/><PanelList title="Son Yüklenen Raporlar" items={reports.slice(0,6).map((x:Report)=>`${x.scout_name||"Scout"} · ${x.score}/10 · ${trDate(x.report_date)}`)}/><PanelList title="Bildirimler" items={notifications.slice(0,8).map((x:Notification)=>`${x.title} · ${x.detail}`)}/></div></section>}
function PanelList({title,items}:any){return <div className="panel glass"><h3>{title}</h3>{items.length?items.map((x:string,i:number)=><div className="rowCard compact" key={i}>{x}</div>):<p>Kayıt yok.</p>}</div>}
function ObservedPlayers({players,openPlayer,add,edit,remove,back}:any){const [query,setQuery]=useState(""); const [sort,setSort]=useState("ScoutCore"); const filtered=sortObserved(players.filter((p:Player)=>`${p.name} ${p.club} ${p.position} ${p.country}`.toLowerCase().includes(query.toLowerCase()))); return <section><Back onClick={back}/><div className="panel pageHead"><div><h2>İzlenen Futbolcular</h2><p>ScoutCore oyuncu havuzu. Oyuncuya tıklayınca ayrı bilgi sayfası açılır.</p></div><div className="actions"><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Oyuncu, kulüp, ülke ara..."/><select value={sort} onChange={e=>setSort(e.target.value)}><option>ScoutCore</option><option>Yıldız</option><option>Potansiyel</option></select><button onClick={add}>+ Futbolcu Ekle</button></div></div><div className="folderBrowser">{positions.map(pos=>{let list=filtered.filter((p:Player)=>p.position===pos); if(sort==="Yıldız")list=[...list].sort((a,b)=>n(b.stars)-n(a.stars)); if(sort==="Potansiyel")list=[...list].sort((a,b)=>n(b.potential_score)-n(a.potential_score)); return <details className="positionFolder" open={list.length>0} key={pos}><summary><b>{pos}</b><span>{list.length} futbolcu</span></summary>{list.map((p:Player,i:number)=><div className="observedCard" key={p.id} onClick={()=>openPlayer(p)}><Avatar p={p}/><div><b>#{i+1} {pos} · {p.name}</b><span>{p.club||"Kulüp yok"} · {p.country||"Ülke yok"}</span><Stars value={p.stars}/></div><Mini label="Scout" value={p.scout_score}/><Mini label="Potansiyel" value={p.potential_score}/><Mini label="Yaş" value={p.age}/><button onClick={(e)=>{e.stopPropagation();edit(p)}}>Düzenle</button><button className="danger" onClick={(e)=>{e.stopPropagation();remove(p)}}>Sil</button></div>)}</details>})}</div></section>}
function PlayerCompare({players,add,openPlayer,back}:any){const sorted=sortObserved(players); const [leftId,setLeftId]=useState(sorted[0]?.id||""); const [rightId,setRightId]=useState(sorted[1]?.id||""); useEffect(()=>{if(!leftId&&sorted[0])setLeftId(sorted[0].id); if(!rightId&&sorted[1])setRightId(sorted[1].id)},[players.length]); const left=players.find((p:Player)=>p.id===leftId)||null; const right=players.find((p:Player)=>p.id===rightId)||null; const rows=[['Yaş','age'],['Mevki','position'],['Kulüp','club'],['Ülke','country'],['Ayak','foot'],['Boy','height'],['Piyasa Değeri','market_value'],['ScoutCore','scout_score'],['Potansiyel','potential_score'],['Hız','speed'],['Teknik','technique'],['Pas','passing'],['Savunma','defending'],['Fizik','physical'],['Mental','mental']]; function val(p:Player|null,k:string){if(!p)return '-'; const v=(p as any)[k]; return v===undefined||v===null||v===''?'-':v} function better(k:string){if(!left||!right)return ''; const scoreKeys=['age','scout_score','potential_score','speed','technique','passing','defending','physical','mental']; if(!scoreKeys.includes(k))return ''; const l=n((left as any)[k]), r=n((right as any)[k]); if(l===r)return ''; if(k==='age')return l<r?'left':'right'; return l>r?'left':'right'} return <section><Back onClick={back}/><div className="panel pageHead compareHead"><div><h2>Oyuncu Karşılaştırma</h2><p>İzlenen futbolcu havuzundan iki oyuncuyu seç ve yan yana değerlendir.</p></div><div className="actions"><button onClick={add}>Oyuncu Ekle</button><button className="ghost" onClick={()=>{setLeftId('');setRightId('')}}>Seçimleri Temizle</button></div></div><div className="comparePicker"><label>1. Oyuncu<select value={leftId} onChange={e=>setLeftId(e.target.value)}><option value="">Oyuncu seç</option>{sorted.map((p:Player)=><option key={p.id} value={p.id}>{p.name} · {p.position} · {p.club||'Kulüp yok'}</option>)}</select></label><div className="vsBadge">VS</div><label>2. Oyuncu<select value={rightId} onChange={e=>setRightId(e.target.value)}><option value="">Oyuncu seç</option>{sorted.map((p:Player)=><option key={p.id} value={p.id}>{p.name} · {p.position} · {p.club||'Kulüp yok'}</option>)}</select></label></div><div className="compareGrid"><CompareCard p={left} side="left" openPlayer={openPlayer} clear={()=>setLeftId('')}/><CompareCard p={right} side="right" openPlayer={openPlayer} clear={()=>setRightId('')}/></div><div className="panel compareTable"><h3>Detaylı Karşılaştırma</h3>{rows.map(([label,key])=>{const b=better(key); return <div className="compareRow" key={key}><span className={b==='left'?'win':''}>{val(left,key)}</span><b>{label}</b><span className={b==='right'?'win':''}>{val(right,key)}</span></div>})}</div></section>}
function CompareCard({p,openPlayer,clear,side}:any){if(!p)return <div className="panel compareCard empty"><b>{side==='left'?'1. Oyuncu':'2. Oyuncu'}</b><p>Karşılaştırmak için oyuncu seç.</p></div>; return <div className="panel compareCard"><div className="compareTop"><Avatar p={p}/><div><h3>{p.name}</h3><p>{p.position} · {p.club||'Kulüp yok'}</p><Stars value={p.stars}/></div></div><div className="compareScores"><Mini label="Scout" value={p.scout_score}/><Mini label="Potansiyel" value={p.potential_score}/><Mini label="Yaş" value={p.age}/></div><div className="compareMeta"><span>{p.foot||'Ayak yok'}</span><span>{p.height||'Boy yok'}</span><span>{p.country||p.nationality||'Ülke yok'}</span></div><div className="compareActions"><button onClick={()=>openPlayer(p)}>Oyuncuyu Aç</button><button className="danger" onClick={clear}>Çıkar</button></div></div>}
function PlayerDetail({p,reports,back,edit}:any){const [tab,setTab]=useState("GENEL"); const ai=aiText(p); return <section><Back onClick={back}/><div className="panel playerDetailHead"><AvatarBig p={p}/><div><h2>{p.name}</h2><p>{p.position} · {p.club||"Kulüp yok"} · {p.country||"Ülke yok"}</p><Stars value={p.stars}/></div><div className="detailScore"><b>{p.scout_score}</b><span>ScoutCore</span><b>{p.potential_score}</b><span>Potansiyel</span></div><button onClick={()=>edit(p)}>Düzenle</button></div><div className="tabStrip">{["GENEL","RAPORLAR","VİDEOLAR","İSTATİSTİK","AI ANALİZ"].map(t=><button key={t} className={tab===t?"active":""} onClick={()=>setTab(t)}>{t}</button>)}</div>{tab==="GENEL"&&<div className="detailGrid"><Info label="Doğum Tarihi" value={trDate(p.birth_date)}/><Info label="Yaş" value={p.age}/><Info label="Mevki" value={p.position}/><Info label="Kulüp" value={p.club}/><Info label="Ülke" value={p.country}/><Info label="Lig" value={p.league}/><Info label="Ayak" value={p.foot}/><Info label="Boy" value={p.height}/><Info label="Durum" value={p.status}/><Info label="Etiket" value={p.tag}/></div>}{tab==="RAPORLAR"&&<div className="twoCols"><div className="panel inner"><h3>Scout Raporu</h3><p>{p.report||"Rapor girilmedi."}</p><h3>Sakatlık Geçmişi</h3><p>{p.injury_history||p.injury_status||"Sakatlık geçmişi girilmedi."}</p><h3>Güçlü Yönler</h3><p>{p.strengths||"-"}</p><h3>Gelişim Alanları</h3><p>{p.weaknesses||"-"}</p></div><div className="panel inner"><h3>Rapor Arşivi</h3>{reports.length?reports.map((r:Report)=><div className="rowCard" key={r.id}><b>{trDate(r.report_date)} · {r.scout_name} · {r.score}/10</b><p>{r.note}</p><span>{r.decision}</span></div>):<p>Rapor yok.</p>}</div></div>}{tab==="VİDEOLAR"&&<div className="panel inner"><h3>Video Merkezi</h3><p>{p.video_url?<a href={p.video_url} target="_blank">Video bağlantısını aç</a>:"Video bağlantısı girilmedi."}</p><p>{p.external_link?<a href={p.external_link} target="_blank">Dış profil bağlantısı</a>:"Dış profil bağlantısı yok."}</p></div>}{tab==="İSTATİSTİK"&&<div className="twoCols"><div className="panel inner"><h3>Radar Grafik</h3><Radar p={p}/></div><div className="panel inner"><h3>Maç İstatistikleri</h3><div className="detailGrid mini"><Info label="Maç" value={p.matches}/><Info label="Gol" value={p.goals}/><Info label="Asist" value={p.assists}/><Info label="Dakika" value={p.minutes}/><Info label="Sarı Kart" value={p.yellow_cards}/><Info label="Kırmızı Kart" value={p.red_cards}/></div></div></div>}{tab==="AI ANALİZ"&&<div className="panel aiPanel"><h3>ScoutCore AI Analiz</h3><p>{ai.summary}</p><div className="kpis"><Kpi title="Süper Lig Uyumu" value={`${ai.fit}/10`}/><Kpi title="Transfer Riski" value={`${ai.risk}/10`} severity={ai.risk>6?"critical":""}/><Kpi title="Potansiyel" value={ai.potential}/><Kpi title="Önerilen Rol" value={ai.role}/></div></div>}</section>}
function Squad({players,openPlayer,add,edit,remove,back}:any){const list=sortSquad(players); return <section><Back onClick={back}/><div className="panel pageHead"><div><h2>Kulüp Kadrosu</h2><p>Tek liste oyuncu takip ekranı. Sıralama mevkiye göre yapılır.</p></div><div className="actions"><button onClick={add}>+ Oyuncu Ekle</button><button onClick={()=>window.print()}>Toplu PDF Raporu</button></div></div><div className="squadTable panel"><div className="squadHead"><b>Adı Soyadı</b><b>Mevki</b><b>Yaş</b><b>Maç</b><b>Gol</b><b>Asist</b><b>Süre</b><b>Sarı Kart</b><b>Kırmızı Kart</b><b>İşlem</b></div>{list.map((p:Player)=><div className="squadRow" key={p.id} onClick={()=>openPlayer(p)}><b>{p.name}</b><span>{p.position}</span><span>{p.age}</span><span>{p.matches}</span><span>{p.goals}</span><span>{p.assists}</span><span>{p.minutes}</span><span className={n(p.yellow_cards)>=3?"warn":""}>{p.yellow_cards||0}</span><span className={n(p.red_cards)>0?"dangerText":""}>{p.red_cards||0}</span><div className="rowActions"><button onClick={(e)=>{e.stopPropagation();edit(p)}}>Düzenle</button><button onClick={(e)=>{e.stopPropagation();window.print()}}>PDF</button><button className="danger" onClick={(e)=>{e.stopPropagation();remove(p)}}>Sil</button></div></div>)}</div></section>}
function SquadDetail({p,back,edit}:any){return <section><Back onClick={back}/><div className="panel playerDetailHead"><AvatarBig p={p}/><div><h2>{p.name}</h2><p>Kulüp Kadrosu Futbolcu Kartı</p></div><button onClick={()=>edit(p)}>Düzenle</button><button onClick={()=>window.print()}>PDF</button></div><div className="detailGrid"><Info label="Doğum Tarihi" value={trDate(p.birth_date)}/><Info label="Yaş" value={p.age}/><Info label="Mevki" value={p.position}/><Info label="Maç" value={p.matches}/><Info label="Gol" value={p.goals}/><Info label="Asist" value={p.assists}/><Info label="Süre" value={p.minutes}/><Info label="Sarı Kart" value={p.yellow_cards}/><Info label="Kırmızı Kart" value={p.red_cards}/></div><div className="twoCols"><div className="panel inner"><h3>Dakika Grafiği</h3><Bars values={[["Dakika",Math.min(10,Math.round(n(p.minutes)/300))],["Gol Katkı",n(p.goals)+n(p.assists)],["Performans",n(p.performance_score)]]}/></div><div className="panel inner"><h3>Kart Alarmı</h3><p>{n(p.red_cards)>0?"Kırmızı kart alarmı.":n(p.yellow_cards)>=4?"4 sarı kart alarmı.":n(p.yellow_cards)===3?"3 sarı kart: ceza sınırı alarmı.":"Kart riski düşük."}</p><h3>Sakatlık Geçmişi</h3><p>{p.injury_history||p.injury_status||"Sakatlık kaydı yok."}</p></div></div></section>}
function WorkspaceView({workspaces,players,token,refresh,setNotice,back}:any){const [w,setW]=useState({club_name:"",season_name:"2026 Yaz",project_name:"",position_focus:"Stoper",target_count:15,status:"Aktif",note:""}); async function add(){if(!w.club_name||!w.project_name){setNotice("Kulüp adı ve proje adı gerekli.");return} try{await insertRow("workspaces",token,w); setW({club_name:"",season_name:"2026 Yaz",project_name:"",position_focus:"Stoper",target_count:15,status:"Aktif",note:""}); refresh()}catch(e:any){setNotice(e.message)}} async function remove(id:string){if(!confirm("Workspace silinsin mi?"))return; try{await deleteRow("workspaces",token,id);refresh()}catch(e:any){setNotice(e.message)}} return <section><Back onClick={back}/><div className="panel pageHead"><h2>Workspace</h2><p>Kulüp → sezon → mevki → oyuncu havuzu → kıyasla → raporla → komiteye gönder.</p></div><div className="panel glass"><div className="filterGrid"><input placeholder="Kulüp adı" value={w.club_name} onChange={e=>setW({...w,club_name:e.target.value})}/><input placeholder="Sezon / dönem" value={w.season_name} onChange={e=>setW({...w,season_name:e.target.value})}/><input placeholder="Proje adı" value={w.project_name} onChange={e=>setW({...w,project_name:e.target.value})}/><select value={w.position_focus} onChange={e=>setW({...w,position_focus:e.target.value})}>{positions.map(p=><option key={p}>{p}</option>)}</select><input placeholder="Hedef oyuncu sayısı" value={w.target_count} onChange={e=>setW({...w,target_count:n(e.target.value)})}/><input placeholder="Not" value={w.note} onChange={e=>setW({...w,note:e.target.value})}/><button onClick={add}>Workspace Ekle</button></div></div><div className="workspaceGrid">{workspaces.map((x:Workspace)=><div className="panel workspaceCard" key={x.id}><h3>{x.club_name}</h3><p>{x.season_name} → {x.project_name} → {x.position_focus}</p><Kpi title="Bu Mevkide Oyuncu" value={players.filter((p:Player)=>p.position===x.position_focus).length}/><div className="actions"><button>Kıyasla</button><button>Raporla</button><button>Komiteye Gönder</button><button className="danger" onClick={()=>remove(x.id)}>Sil</button></div><p>{x.note}</p></div>)}</div></section>}
function CommitteeView({players,committee,comments,token,refresh,setNotice,back}:any){const [draft,setDraft]=useState({player_id:"",priority:"Normal",transfer_type:"Satın Alma",fee:"",salary:"",committee_note:"",decision_status:"Bekliyor"}); const [comment,setComment]=useState({author:"Onur Baş",comment_text:"",vote_type:"Beklet"}); const selected=players.find((p:Player)=>p.id===draft.player_id); async function add(){if(!selected){setNotice("Futbolcu seç.");return} try{await insertRow("transfer_committee",token,{...draft,player_name:selected.name,stage:"Komite",yes_votes:0,no_votes:0}); refresh()}catch(e:any){setNotice(e.message)}} async function remove(id:string){if(!confirm("Komite kaydı silinsin mi?"))return; try{await deleteRow("transfer_committee",token,id); refresh()}catch(e:any){setNotice(e.message)}} async function addComment(id:string,vote:string){try{await insertRow("transfer_committee_comments",token,{committee_id:id,author:comment.author,comment_text:comment.comment_text||vote,vote_type:vote}); setComment({...comment,comment_text:""}); refresh()}catch(e:any){setNotice(e.message)}} async function decision(id:string,decision_status:string){await updateRow("transfer_committee",token,id,{decision_status}); refresh()} return <section><Back onClick={back}/><div className="panel pageHead"><h2>Transfer Komitesi</h2><p>WhatsApp mantığında yorum, oy, karar ve onay akışı.</p></div><div className="panel glass"><div className="filterGrid"><select value={draft.player_id} onChange={e=>setDraft({...draft,player_id:e.target.value})}><option value="">Oyuncu seç</option>{players.map((p:Player)=><option key={p.id} value={p.id}>{p.name} - {p.position}</option>)}</select><select value={draft.priority} onChange={e=>setDraft({...draft,priority:e.target.value})}><option>Normal</option><option>Yüksek</option><option>Acil</option></select><select value={draft.transfer_type} onChange={e=>setDraft({...draft,transfer_type:e.target.value})}><option>Satın Alma</option><option>Kiralık</option><option>Serbest</option></select><input placeholder="Maliyet" value={draft.fee} onChange={e=>setDraft({...draft,fee:e.target.value})}/><input placeholder="Maaş" value={draft.salary} onChange={e=>setDraft({...draft,salary:e.target.value})}/><input placeholder="İlk komite notu" value={draft.committee_note} onChange={e=>setDraft({...draft,committee_note:e.target.value})}/><button onClick={add}>Komiteye Ekle</button></div></div><div className="chatList">{committee.map((c:Committee)=><div className="chatCard panel" key={c.id}><div className="chatHead"><div><b>{c.player_name}</b><span>{c.priority} · {c.transfer_type} · {c.decision_status}</span></div><button className="danger" onClick={()=>remove(c.id)}>Sil</button></div><p>{c.committee_note}</p><div className="chatMessages">{comments.filter((m:CommitteeComment)=>m.committee_id===c.id).map(m=><div className="message" key={m.id}><b>{m.author}</b><p>{m.comment_text}</p><span>{m.vote_type}</span></div>)}</div><div className="chatInput"><input placeholder="Yorum yaz" value={comment.comment_text} onChange={e=>setComment({...comment,comment_text:e.target.value})}/><button onClick={()=>addComment(c.id,"👍")}>👍</button><button onClick={()=>addComment(c.id,"👎")}>👎</button><button onClick={()=>addComment(c.id,"Beklet")}>Beklet</button><button onClick={()=>decision(c.id,"Onaylandı")}>Onay</button></div></div>)}</div></section>}
function ScoutManagement({scouts,token,refresh,setNotice,back}:any){const [s,setS]=useState({name:"",region:"",role:"Scout",assignment:"",match_name:"",player_name:"",due_date:"",status:"Bekliyor"}); async function add(){if(!s.name){setNotice("Scout adı zorunlu.");return} try{await insertRow("scouts",token,{...s,due_date:s.due_date||null,reports_count:0}); setS({name:"",region:"",role:"Scout",assignment:"",match_name:"",player_name:"",due_date:"",status:"Bekliyor"}); refresh()}catch(e:any){setNotice(e.message)}} async function remove(id:string){if(!confirm("Scout silinsin mi?"))return; try{await deleteRow("scouts",token,id);refresh()}catch(e:any){setNotice(e.message)}} return <section><Back onClick={back}/><div className="panel pageHead"><h2>Scout Yönetimi</h2><p>Scout ekleme, çıkarma ve görevlendirme.</p></div><div className="panel glass"><div className="filterGrid"><input placeholder="Scout adı" value={s.name} onChange={e=>setS({...s,name:e.target.value})}/><input placeholder="Bölge" value={s.region} onChange={e=>setS({...s,region:e.target.value})}/><input placeholder="Rol" value={s.role} onChange={e=>setS({...s,role:e.target.value})}/><input placeholder="Maç" value={s.match_name} onChange={e=>setS({...s,match_name:e.target.value})}/><input placeholder="Oyuncu" value={s.player_name} onChange={e=>setS({...s,player_name:e.target.value})}/><input type="date" value={s.due_date} onChange={e=>setS({...s,due_date:e.target.value})}/><button onClick={add}>Scout Ekle / Görevlendir</button></div></div><div className="kanban">{["Bekliyor","İzleniyor","Tamamlandı"].map(st=><div className="kanbanCol" key={st}><h3>{st}</h3>{scouts.filter((x:Scout)=>x.status===st).map((x:Scout)=><div className="rowCard" key={x.id}><b>{x.name}</b><p>{x.match_name||"Maç yok"} · {x.player_name||"Oyuncu yok"}</p><span>{trDate(x.due_date)}</span><button className="danger" onClick={()=>remove(x.id)}>Sil</button></div>)}</div>)}</div></section>}
function AgendaView({agenda,token,refresh,setNotice,back}:any){const [a,setA]=useState({plan_date:today,title:"",detail:"",plan_type:"Plan"}); const d=new Date(); const days=new Date(d.getFullYear(),d.getMonth()+1,0).getDate(); async function add(){if(!a.title)return; try{await insertRow("agenda",token,a); setA({plan_date:today,title:"",detail:"",plan_type:"Plan"}); refresh()}catch(e:any){setNotice(e.message)}} return <section><Back onClick={back}/><div className="panel pageHead"><h2>Ajanda</h2><p>Güncel takvim ve operasyon planlama alanı.</p></div><div className="panel glass"><div className="filterGrid"><input type="date" value={a.plan_date} onChange={e=>setA({...a,plan_date:e.target.value})}/><input placeholder="Başlık" value={a.title} onChange={e=>setA({...a,title:e.target.value})}/><input placeholder="Detay" value={a.detail} onChange={e=>setA({...a,detail:e.target.value})}/><select value={a.plan_type} onChange={e=>setA({...a,plan_type:e.target.value})}><option>Plan</option><option>Maç</option><option>Scout</option><option>Toplantı</option></select><button onClick={add}>Ajandaya Ekle</button></div></div><div className="calendarGrid">{Array.from({length:days},(_,i)=>{const day=String(i+1).padStart(2,"0"); const month=String(d.getMonth()+1).padStart(2,"0"); const key=`${d.getFullYear()}-${month}-${day}`; const items=agenda.filter((x:Agenda)=>x.plan_date===key); return <div className="calDay" key={key}><b>{day}</b>{items.map(x=><span key={x.id}>{x.title}</span>)}</div>})}</div></section>}
function NotificationCenter({notifications,back}:any){return <section><Back onClick={back}/><div className="panel pageHead"><h2>Bildirim Merkezi</h2><p>Renk kodlu operasyon uyarıları.</p></div>{notifications.map((n:Notification,i:number)=><div className={`notify ${n.severity||"Bilgi"}`} key={n.id||i}><b>{badge(n.severity)} {n.title}</b><p>{n.detail}</p><span>{n.notification_type}</span></div>)}</section>}
function badge(s?:string){return s==="Kritik"?"🔴":s==="Önemli"?"🟠":s==="Uyarı"?"🟡":"🟢"}
function Contact({back}:any){return <section><Back onClick={back}/><div className="panel contact"><h2>İletişim</h2><p>ScoutCore proje iletişim bilgileri.</p><div className="contactCard"><b>Onur Baş</b><span>Mail: onur_bas@outlook.com.tr</span></div></div></section>}
function Settings({players,back}:any){return <section><Back onClick={back}/><div className="panel"><h2>Ayarlar</h2><p>ScoutCore V15 Elite Türkçe sürüm.</p><button onClick={()=>window.print()}>PDF Yazdır</button></div></section>}
function PlayerEditor({player,scope,save,cancel}:any){const [p,setP]=useState<Player>(player); function u(k:keyof Player,v:any){setP({...p,[k]:v})} return <div className="modal"><div className="editor"><h2>{p.id?"Futbolcuyu Düzenle":"Futbolcu Ekle"}</h2><div className="editorGrid"><input placeholder="Adı soyadı" value={p.name} onChange={e=>u("name",e.target.value)}/><select value={p.position} onChange={e=>u("position",e.target.value)}>{positions.map(x=><option key={x}>{x}</option>)}</select><input type="date" value={dateValue(p.birth_date)} onChange={e=>u("birth_date",e.target.value)}/><input placeholder="Yaş" value={p.age||""} onChange={e=>u("age",n(e.target.value))}/>{scope==="scout"&&<><input placeholder="Kulüp" value={p.club} onChange={e=>u("club",e.target.value)}/><input placeholder="Ülke" value={p.country} onChange={e=>u("country",e.target.value)}/><input placeholder="Lig" value={p.league||""} onChange={e=>u("league",e.target.value)}/><input placeholder="Ayak" value={p.foot} onChange={e=>u("foot",e.target.value)}/><input placeholder="Boy" value={p.height} onChange={e=>u("height",e.target.value)}/><input placeholder="ScoutCore 0-10" value={p.scout_score||""} onChange={e=>u("scout_score",clamp10(e.target.value))}/><input placeholder="Potansiyel 0-10" value={p.potential_score||""} onChange={e=>u("potential_score",clamp10(e.target.value))}/><input placeholder="Yıldız 0-5" value={p.stars||""} onChange={e=>u("stars",Math.max(0,Math.min(5,Math.round(n(e.target.value)))))}/><input placeholder="Video linki" value={p.video_url} onChange={e=>u("video_url",e.target.value)}/><input placeholder="Dış profil linki" value={p.external_link} onChange={e=>u("external_link",e.target.value)}/></>}
 <input placeholder="Maç" value={p.matches||""} onChange={e=>u("matches",n(e.target.value))}/><input placeholder="Gol" value={p.goals||""} onChange={e=>u("goals",n(e.target.value))}/><input placeholder="Asist" value={p.assists||""} onChange={e=>u("assists",n(e.target.value))}/><input placeholder="Süre / dakika" value={p.minutes||""} onChange={e=>u("minutes",n(e.target.value))}/><input placeholder="Sarı kart" value={p.yellow_cards||""} onChange={e=>u("yellow_cards",n(e.target.value))}/><input placeholder="Kırmızı kart" value={p.red_cards||""} onChange={e=>u("red_cards",n(e.target.value))}/></div>{scope==="scout"&&<><h3>Radar Değerleri</h3><div className="editorGrid"><input placeholder="Hız 0-10: sprint, çabukluk" value={p.speed||""} onChange={e=>u("speed",clamp10(e.target.value))}/><input placeholder="Teknik 0-10: ilk kontrol, top hakimiyeti" value={p.technique||""} onChange={e=>u("technique",clamp10(e.target.value))}/><input placeholder="Pas 0-10: kısa/uzun pas" value={p.passing||""} onChange={e=>u("passing",clamp10(e.target.value))}/><input placeholder="Savunma 0-10: markaj, müdahale" value={p.defending||""} onChange={e=>u("defending",clamp10(e.target.value))}/><input placeholder="Fizik 0-10: güç, temas" value={p.physical||""} onChange={e=>u("physical",clamp10(e.target.value))}/><input placeholder="Hava Hakimiyeti 0-10" value={p.aerial||""} onChange={e=>u("aerial",clamp10(e.target.value))}/><input placeholder="Karar Verme 0-10" value={p.decision_making||""} onChange={e=>u("decision_making",clamp10(e.target.value))}/><input placeholder="Mental 0-10" value={p.mental||""} onChange={e=>u("mental",clamp10(e.target.value))}/></div></>}<label className="fullLabel">Rapor / Performans Notu<textarea value={p.report} onChange={e=>u("report",e.target.value)} placeholder="Genel rapor"/></label><label className="fullLabel">Sakatlık Geçmişi<textarea value={p.injury_history||""} onChange={e=>u("injury_history",e.target.value)} placeholder="Sakatlık geçmişi"/></label><div className="modalActions"><button onClick={()=>save(p)}>Kaydet</button><button onClick={cancel}>Vazgeç</button></div></div></div>}
function generatedNotifications(players:Player[], scouts:Scout[], reports:Report[]):Notification[]{const ns:Notification[]=[];players.filter(p=>n(p.yellow_cards)===3).forEach(p=>ns.push({title:"3 Sarı Kart Alarmı",detail:`${p.name} ceza sınırına yaklaştı.`,notification_type:"Kart",severity:"Uyarı"}));players.filter(p=>n(p.yellow_cards)>=4||n(p.red_cards)>0).forEach(p=>ns.push({title:"Cezalı Oyuncu Alarmı",detail:`${p.name} kart nedeniyle kontrol edilmeli.`,notification_type:"Kart",severity:"Kritik"}));scouts.filter(s=>s.due_date&&s.due_date<=today&&s.status!=="Tamamlandı").forEach(s=>ns.push({title:"Scout görevi bekliyor",detail:`${s.name}: ${s.match_name||"Görev"}`,notification_type:"Görev",severity:"Önemli"}));reports.slice(0,5).forEach(r=>ns.push({title:"Yeni scout raporu",detail:`${r.scout_name||"Scout"} rapor ekledi.`,notification_type:"Rapor",severity:"Bilgi"}));return ns;}
function Avatar({p}:{p:Player}){return <div className="avatar">{p.photo_url?<img src={p.photo_url}/>:p.name.slice(0,2)}</div>}
function AvatarBig({p}:{p:Player}){return <div className="avatar big">{p.photo_url?<img src={p.photo_url}/>:p.name.slice(0,2)}</div>}
function Mini({label,value}:any){return <div className="scoreMini"><span>{label}</span><b>{value ?? 0}</b></div>}
function Info({label,value}:any){return <div className="info"><span>{label}</span><b>{value ?? "-"}</b></div>}
function Stars({value}:any){return <div className="stars">{[1,2,3,4,5].map(s=><span key={s} className={n(value)>=s?"star on":"star"}>★</span>)}<small>{value||0}/5</small></div>}
function Radar({p}:any){const vals=[["Hız",p.speed],["Teknik",p.technique],["Pas",p.passing],["Savunma",p.defending],["Fizik",p.physical],["Hava",p.aerial],["Karar",p.decision_making],["Mental",p.mental]];const pts=vals.map((v,i)=>{const a=(-90+i*360/vals.length)*Math.PI/180;const r=25+n(v[1])*11;return `${150+Math.cos(a)*r},${150+Math.sin(a)*r}`}).join(" ");return <div className="radarWrap"><svg viewBox="0 0 300 300"><polygon points="150,35 231,69 265,150 231,231 150,265 69,231 35,150 69,69" className="radarGrid"/><polygon points={pts} className="radarPoly"/></svg><div className="radarList">{vals.map(v=><Info key={v[0]} label={v[0]} value={`${v[1]||0}/10`}/>)}</div></div>}
function Bars({values}:any){return <div>{values.map((v:any)=><div className="bar" key={v[0]}><div><span>{v[0]}</span><b>{v[1]}</b></div><i><em style={{width:`${Math.min(100,n(v[1])*10)}%`}}/></i></div>)}</div>}
function aiText(p:Player){const fit=Math.round((n(p.scout_score)*.55+n(p.potential_score)*.35+n(p.stars)*.2)*10)/10;const risk=n(p.yellow_cards)>=4||n(p.red_cards)>0?8:n(p.scout_score)<6?6:3;return {fit,risk,potential:n(p.potential_score)>=8?"Yüksek":"Takip",role:p.position,summary:`${p.name} için mevcut veri setine göre ScoutCore skoru ${p.scout_score}/10. Güçlü yönler: ${p.strengths||"henüz girilmedi"}. Gelişim alanları: ${p.weaknesses||"henüz girilmedi"}. Süper Lig uyumu ${fit}/10 olarak değerlendirildi.`}}
